// 1. Parse existing Notion pages (if any are returned)
let existingPages = [];
try {
  existingPages = $('Notion - Fetch All Pages').all().map(item => {
    const props = item.json;
    return {
      problemNumber: (props['Problem Number'] || '').toString().trim().padStart(4, '0'),
      language: (props['Language'] || '').toString().trim()
    };
  });
} catch (e) {
  existingPages = [];
}

// Create an optimization set for instant lookup: "problemNumber_Language"
const existingSet = new Set(existingPages.map(p => `${p.problemNumber}_${p.language}`));

// 2. Filter solution files from GitHub Tree
const tree = $('GitHub - List All Files').first().json.tree;
const solutionFiles = tree.filter(item => {
  if (item.type !== 'blob') return false;
  const path = item.path;
  const ext = ['.py', '.java', '.cpp', '.js', '.ts', '.go', '.rs', '.kt', '.cs', '.rb'];
  return ext.some(e => path.endsWith(e)) && path.includes('/');
});

// 3. Extract metadata and filter out duplicates
const solutions = [];
for (const f of solutionFiles) {
  const parts = f.path.split('/');
  const folder = parts[0];
  const filename = parts[parts.length - 1];
  const ext = filename.split('.').pop();

  const langMap = {
    py: 'Python', java: 'Java', cpp: 'C++', js: 'JavaScript',
    ts: 'TypeScript', go: 'Go', rs: 'Rust', kt: 'Kotlin',
    cs: 'C#', rb: 'Ruby'
  };

  const match = folder.match(/^(\d+)[^a-zA-Z]*(.*)/); 
  const problemNumber = match ? match[1].padStart(4, '0') : '0000';
  const rawName = match ? match[2].replace(/-/g, ' ').trim() : folder;
  const problemName = rawName.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  const language = langMap[ext] || ext.toUpperCase();

  // Check lookup key
  const lookupKey = `${problemNumber}_${language}`;
  if (!existingSet.has(lookupKey)) {
    solutions.push({
      path: f.path,
      sha: f.sha,
      folder: folder,
      filename: filename,
      language: language,
      extension: ext,
      problemNumber: problemNumber,
      problemName: problemName
    });
  }
}

// Temporarily slice to 1 item for a safe run-test
// Change to return solutions.map(s => ({ json: s })); once verified!
return solutions.slice(0, 1).map(s => ({ json: s }));

const item = $input.item.json;
const encoded = item.content.replace(/\n/g, '');
const decoded = Buffer.from(encoded, 'base64').toString('utf-8');

const prev = $('Filter & Parse Solution Files').item.json;

return {
  json: {
    ...prev,
    code: decoded,
    githubUrl: item.html_url,
    downloadUrl: item.download_url
  }
};

// Parse AI response and merge with file metadata
const aiResponse = $input.first().json;
const fileData = $('Decode Base64 Code').first().json;

let analysisText = '';
try {
  analysisText = aiResponse.choices[0].message.content;
  // Strip markdown code fences if present
  analysisText = analysisText.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
} catch(e) {
  throw new Error('Could not extract AI text: ' + e.message);
}

let analysis;
try {
  analysis = JSON.parse(analysisText);
} catch(e) {
  throw new Error('JSON parse failed: ' + e.message + '\nRaw: ' + analysisText.substring(0, 500));
}

// Override with known metadata
analysis.problem_number = fileData.problemNumber;
analysis.problem_name = fileData.problemName;
analysis.language = fileData.language;
analysis.github_url = fileData.githubUrl;
analysis.leetcode_url = `https://leetcode.com/problems/${fileData.folder.replace(/^\d+-/, '')}/`;

return [{ json: analysis }];

// Build NeetCode URL from problem name
const data = $input.first().json;
const slug = data.problem_name
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .trim()
  .replace(/\s+/g, '-');

const neetcodeUrl = `https://neetcode.io/problems/${slug}`;
const youtubeSearchUrl = `https://www.youtube.com/results?search_query=neetcode+${encodeURIComponent(data.problem_name)}`;

return [{ json: { ...data, neetcode_url: neetcodeUrl, youtube_search: youtubeSearchUrl } }];

// Build NeetCode URL from problem name
const data = $input.first().json;
const slug = data.problem_name
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .trim()
  .replace(/\s+/g, '-');

const neetcodeUrl = `https://neetcode.io/problems/${slug}`;
const youtubeSearchUrl = `https://www.youtube.com/results?search_query=neetcode+${encodeURIComponent(data.problem_name)}`;

return [{ json: { ...data, neetcode_url: neetcodeUrl, youtube_search: youtubeSearchUrl } }];

// Build Notion blocks for the page content
const d = $('Build NeetCode URL').first().json;
const pageId = $input.first().json.id;

const heading = (text, level = 2) => ({
  object: 'block',
  type: `heading_${level}`,
  [`heading_${level}`]: {
    rich_text: [{ type: 'text', text: { content: text } }]
  }
});

const paragraph = (text) => ({
  object: 'block',
  type: 'paragraph',
  paragraph: {
    rich_text: [{ type: 'text', text: { content: String(text || '') } }]
  }
});

const bullet = (text) => ({
  object: 'block',
  type: 'bulleted_list_item',
  bulleted_list_item: {
    rich_text: [{ type: 'text', text: { content: String(text || '') } }]
  }
});

const divider = () => ({ object: 'block', type: 'divider', divider: {} });

const codeBlock = (code, lang = 'plain text') => ({
  object: 'block',
  type: 'code',
  code: {
    language: lang.toLowerCase().replace('c++', 'c').replace('javascript', 'javascript').replace('typescript', 'typescript').replace('python', 'python').replace('java', 'java').replace('go', 'go').replace('rust', 'rust').replace('kotlin', 'kotlin'),
    rich_text: [{ type: 'text', text: { content: String(code || '').substring(0, 2000) } }]
  }
});

const callout = (text, emoji = '💡') => ({
  object: 'block',
  type: 'callout',
  callout: {
    icon: { type: 'emoji', emoji },
    rich_text: [{ type: 'text', text: { content: String(text || '') } }]
  }
});

const blocks = [
  heading('📌 Problem Info', 2),
  paragraph(`Difficulty: ${d.difficulty} | Language: ${d.language} | Topic: ${d.topic} | Subtopic: ${d.subtopic}`),
  paragraph(`Algorithm: ${d.algorithm} | Pattern: ${d.pattern}`),
  divider(),

  heading('🧠 Intuition', 2),
  callout(d.intuition, '🧠'),
  divider(),

  heading('🪜 Step-by-Step Logic', 2),
  ...(Array.isArray(d.step_by_step_logic) ? d.step_by_step_logic.map((s, i) => bullet(`${i+1}. ${s}`)) : [paragraph(String(d.step_by_step_logic))]),
  divider(),

  heading('🔍 Line-by-Line Explanation', 2),
  ...(Array.isArray(d.line_by_line_explanation) ? d.line_by_line_explanation.map(l => bullet(l)) : [paragraph(String(d.line_by_line_explanation))]),
  divider(),

  heading('🎯 Dry Run / Trace', 2),
  codeBlock(d.dry_run, 'plain text'),
  divider(),

  heading('⏱️ Complexity Analysis', 2),
  paragraph(`Time Complexity: ${d.time_complexity}`),
  paragraph(`Space Complexity: ${d.space_complexity}`),
  divider(),

  heading('🔄 Alternative Approaches', 2),
  ...(Array.isArray(d.alternative_solutions) ? d.alternative_solutions.map(a => bullet(a)) : [paragraph(String(d.alternative_solutions))]),
  divider(),

  heading('🚀 Optimization Notes', 2),
  callout(d.better_optimization, '🚀'),
  divider(),

  heading('⚠️ Common Mistakes', 2),
  ...(Array.isArray(d.common_mistakes) ? d.common_mistakes.map(m => bullet(m)) : [paragraph(String(d.common_mistakes))]),
  divider(),

  heading('🎤 Interview Tips', 2),
  callout(d.interview_tips, '🎤'),
  divider(),

  heading('📝 Revision Notes', 2),
  ...(Array.isArray(d.revision_notes) ? d.revision_notes.map(r => bullet(r)) : [paragraph(String(d.revision_notes))]),
  divider(),

  heading('🃏 Flashcards', 2),
  ...(Array.isArray(d.flashcards) ? d.flashcards.map(f => {
    const fc = typeof f === 'object' ? `Q: ${f.question || f.q || f} | A: ${f.answer || f.a || ''}` : String(f);
    return callout(fc, '🃏');
  }) : [paragraph(String(d.flashcards))]),
  divider(),

  heading('🔗 Related Problems', 2),
  ...(Array.isArray(d.related_questions) ? d.related_questions.map(r => bullet(r)) : [paragraph(String(d.related_questions))]),
  divider(),

  heading('🔗 Links', 2),
  paragraph(`GitHub: ${d.github_url}`),
  paragraph(`LeetCode: ${d.leetcode_url}`),
  paragraph(`NeetCode: ${d.neetcode_url}`),
  paragraph(`YouTube Search: ${d.youtube_search}`)
];

return [{ json: { pageId, blocks } }];

// Aggregate results and build summary
const allItems = $input.all();
const processed = allItems.length;

return [{
  json: {
    summary: {
      total_processed: processed,
      timestamp: new Date().toISOString(),
      message: `Historical import complete. ${processed} problems imported into Notion.`
    }
  }
}];
